mapper.select:
SELECT a.*, u.nickname AS applicant_name, d.dept_name AS dept_name, au.nickname AS approver_name FROM asset_application a LEFT JOIN sys_user u ON a.applicant_id = u.user_id LEFT JOIN sys_dept d ON a.dept_id = d.dept_id LEFT JOIN sys_user au ON a.approver_id = au.user_id WHERE a.deleted = 0
AND a.applicant_id = #{applicantId}
AND a.status = #{status}
ORDER BY a.create_time DESC
